// 三载体一致：按裁剪几何调用 jsPDF 原生 API，只产 Blob
import { jsPDF } from 'https://cdn.jsdelivr.net/npm/jspdf@4/+esm';
const d=data.document, doc=new jsPDF({orientation:d.orientation??'portrait',unit:d.unit??'mm',format:d.format??'a4',compress:d.compress??false,putOnlyUsedFonts:d.putOnlyUsedFonts??false});
for (const [i,p] of d.pages.entries()) { if(i) doc.addPage(); for(const t of p.texts??[]) { doc.setFont(t.font??'helvetica',t.fontStyle??'normal'); doc.setFontSize(t.fontSize??16); doc.setTextColor(t.color??'#000000'); doc.text(t.text,t.x,t.y,t.options??{}); } }
const blob = doc.output('blob');
